// MARK: - Secure Storage Helper
final class SecureStorage {
    
    private static let service = "com.app.authentication"
    private static let authenticatedKey = "userAuthenticated"
    private static let biometricEnabledKey = "biometricEnabled"
    private static let authTokenKey = "authToken"
    
    static func store(key: String, data: Data) -> Bool {
        // Delete existing item first
        delete(key: key)
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenPasscodeSetThisDeviceOnly
        ]
        
        let status = SecItemAdd(query as CFDictionary, nil)
        return status == errSecSuccess
    }
    
    static func storeWithBiometricProtection(key: String, data: Data) -> Bool {
        delete(key: key)
        
        guard let accessControl = SecAccessControlCreateWithFlags(
            kCFAllocatorDefault,
            kSecAttrAccessibleWhenPasscodeSetThisDeviceOnly,
            .biometryCurrentSet,
            nil
        ) else {
            return false
        }
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessControl as String: accessControl
        ]
        
        let status = SecItemAdd(query as CFDictionary, nil)
        return status == errSecSuccess
    }
    
    static func retrieve(key: String, context: LAContext? = nil) -> Data? {
        var query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        if let context = context {
            query[kSecUseAuthenticationContext as String] = context
        }
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess else { return nil }
        return result as? Data
    }
    
    static func delete(key: String) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
    }
    
    // Convenience methods
    static func setBiometricEnabled(_ enabled: Bool) {
        let data = Data([enabled ? 1 : 0])
        _ = store(key: biometricEnabledKey, data: data)
    }
    
    static func isBiometricEnabled() -> Bool {
        guard let data = retrieve(key: biometricEnabledKey) else { return false }
        return data.first == 1
    }
    
    static func storeAuthToken(_ token: String) -> Bool {
        guard let data = token.data(using: .utf8) else { return false }
        return storeWithBiometricProtection(key: authTokenKey, data: data)
    }
    
    static func retrieveAuthToken(context: LAContext) -> String? {
        guard let data = retrieve(key: authTokenKey, context: context) else { return nil }
        return String(data: data, encoding: .utf8)
    }
    
    static func clearAll() {
        delete(key: authenticatedKey)
        delete(key: biometricEnabledKey)
        delete(key: authTokenKey)
    }
}

