        case biometryNotAvailable
        case biometryNotEnrolled
        case biometryLockout
        case userCancel
        case userFallback
        case authenticationFailed
        case systemCancel
        case passcodeNotSet
        case invalidContext
        case unknown(Error)
        
        var errorDescription: String? {
            switch self {
            case .biometryNotAvailable:
                return "Biometric authentication is not available on this device."
            case .biometryNotEnrolled:
                return "No biometric data is enrolled. Please set up Face ID or Touch ID in Settings."
            case .biometryLockout:
                return "Biometric authentication is locked due to too many failed attempts. Please use your passcode."
            case .userCancel:
                return "Authentication was cancelled."
            case .userFallback:
                return "User chose to enter password."
            case .authenticationFailed:
                return "Authentication failed. Please try again."
            case .systemCancel:
                return "Authentication was cancelled by the system."
            case .passcodeNotSet:
                return "A device passcode is required to use biometric authentication."
            case .invalidContext:
                return "Authentication context is invalid."
            case .unknown(let error):
                return error.localizedDescription
            }
        }
    }
    
    var availableBiometricType: BiometricType {
        let context = LAContext()
        var error: NSError?
        
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            return .none
        }
        
        switch context.biometryType {
        case .touchID:
            return .touchID
        case .faceID:
            return .faceID
        case .opticID:
            return .opticID
        case .none:
            return .none
        @unknown default:
            return .none
        }
    }
    
    var biometricDisplayName: String {
        switch availableBiometricType {
        case .faceID: return "Face ID"
        case .touchID: return "Touch ID"
        case .opticID: return "Optic ID"
        case .none: return "Biometric Authentication"
        }
    }
    
    var isBiometricAvailable: Bool {
        let context = LAContext()
        var error: NSError?
        return context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error)
    }
    
    /// Evaluates the current biometric enrollment state to detect changes
    /// (e.g., new fingerprint added, Face ID re-enrolled)
    func evaluateBiometricDomainState() -> Data? {
        let context = LAContext()
        var error: NSError?
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            return nil
        }
        return context.evaluatedPolicyDomainState
    }
    
    /// Authenticate using biometrics with strong policy (biometrics only, no device passcode fallback)
    func authenticateWithBiometrics(
        reason: String,
        completion: @escaping (Result<LAContext, AuthenticationError>) -> Void
    ) {
        let context = LAContext()
        // Disable fallback to password in the biometric prompt
        context.localizedFallbackTitle = "Enter Password"
        // Set interaction not allowed timeout
        context.touchIDAuthenticationAllowableReuseDuration = 0
        
        var error: NSError?
        
        // Use .deviceOwnerAuthenticationWithBiometrics to require actual biometric auth
        // NOT .deviceOwnerAuthentication which falls back to device passcode
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            let authError = mapLAError(error)
            DispatchQueue.main.async {
                completion(.failure(authError))
            }
            return
        }
        
        context.evaluatePolicy(
            .deviceOwnerAuthenticationWithBiometrics,
            localizedReason: reason
        ) { success, evaluationError in
            DispatchQueue.main.async {
                if success {
                    completion(.success(context))
                } else if let error = evaluationError {
                    completion(.failure(self.mapLAError(error as NSError?)))
                } else {
                    completion(.failure(.authenticationFailed))
                }
            }
        }
    }
    
    /// Authenticate and retrieve stored auth token
    func authenticateAndRetrieveToken(
        reason: String,
        completion: @escaping (Result<String, AuthenticationError>) -> Void
    ) {
        authenticateWithBiometrics(reason: reason) { result in
            switch result {
            case .success(let context):
                if let token = SecureStorage.retrieveAuthToken(context: context) {
                    completion(.success(token))
                } else {
                    completion(.failure(.authenticationFailed))
                }
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    private func mapLAError(_ error: NSError?) -> AuthenticationError {
        guard let error = error else { return .authenticationFailed }
        
        switch error.code {
        case LAError.biometryNotAvailable.rawValue:
            return .biometryNotAvailable
        case LAError.biometryNotEnrolled.rawValue:
            return .biometryNotEnrolled
        case LAError.biometryLockout.rawValue:
            return .biometryLockout
        case LAError.userCancel.rawValue:
            return .userCancel
        case LAError.userFallback.rawValue:
            return .userFallback
        case LAError.authenticationFailed.rawValue:
            return .authenticationFailed
        case LAError.systemCancel.rawValue:
            return .systemCancel
        case LAError.passcodeNotSet.rawValue:
            return .passcodeNotSet
        case LAError.invalidContext.rawValue:
            return .invalidContext
        default:
            return .unknown(error)
        }
    }
}

