            DispatchQueue.main.async {
                self.isLoading = false
                
                if isValid {
                    let token = "authenticated_token_\(UUID().uuidString)"
                    self.handleSuccessfulAuthentication(token: token)
                    
                    // Offer to enable biometric auth if available and not already enabled
