        showBiometricPrompt = false
    }
    
    // MARK: - Private Methods
    
    private func handleSuccessfulAuthentication(token: String) {
        isAuthenticated = true
        showPasswordLogin = false
        showBiometricPrompt = false
        authError = nil
        retryCount = 0
        
