            showPasswordLogin = true
            authError = nil
            
        case .userFallback:
            showPasswordLogin = true
            authError = nil
            
        case .biometryLockout:
            authError = error.errorDescription
            showPasswordLogin = true
            
        case .biometryNotAvailable, .biometryNotEnrolled:
            authError = error.errorDescription
            SecureStorage.setBiometricEnabled(false)
            showPasswordLogin = true
            
        case .authenticationFailed:
