    private let loginButton = UIButton(type: .system)
    private let biometricButton = UIButton(type: .system)
    private let errorLabel = UILabel()
    private let activityIndicator = UIActivityIndicatorView(style: .large)
    
    var onAuthenticationSuccess: (() -> Void)?
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        setupNotifications()
        
        // Attempt biometric auth on launch if enabled
        if authManager.shouldAttemptBiometricAuth {
            attemptBiometricAuth()
        } else {
            showPasswordFields()
        }
    }
    
    deinit {
        NotificationCenter.default.removeObserver(self)
    }
    
    // MARK: - UI Setup
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        
        // Title
        titleLabel.text = "Welcome Back"
        titleLabel.font = .systemFont(ofSize: 28, weight: .bold)
        titleLabel.textAlignment = .center
        
        // Subtitle
        subtitleLabel.text = "Sign in to continue"
        subtitleLabel.font = .systemFont(ofSize: 16)
        subtitleLabel.textColor = .secondaryLabel
        subtitleLabel.textAlignment = .center
        
        // Username
        usernameTextField.placeholder = "Username"
        usernameTextField.borderStyle = .roundedRect
        usernameTextField.autocapitalizationType = .none
        usernameTextField.autocorrectionType = .no
        usernameTextField.textContentType = .username
        usernameTextField.returnKeyType = .next
        usernameTextField.isHidden = true
        
        // Password
        passwordTextField.placeholder = "Password"
        passwordTextField.borderStyle = .roundedRect
        passwordTextField.isSecureTextEntry = true
        passwordTextField.textContentType = .password
        passwordTextField.returnKeyType = .done
        passwordTextField.isHidden = true
        
        // Login Button
        loginButton.setTitle("Sign In", for: .normal)
        loginButton.titleLabel?.font = .systemFont(ofSize: 18, weight: .semibold)
        loginButton.backgroundColor = .systemBlue
        loginButton.setTitleColor(.white, for: .normal)
        loginButton.layer.cornerRadius = 12
        loginButton.heightAnchor.constraint(equalToConstant: 50).isActive = true
        loginButton.addTarget(self, action: #selector(loginButtonTapped), for: .touchUpInside)
        loginButton.isHidden = true
        
        // Biometric Button
        let biometricType = biometricManager.availableBiometricType
        let biometricIcon: String
        switch biometricType {
        case .faceID:
            biometricIcon = "faceid"
        case .touchID:
            biometricIcon = "touchid"
        default:
            biometricIcon = "lock.shield"
        }
        
        let config = UIImage.SymbolConfiguration(pointSize: 40, weight: .regular)
        biometricButton.setImage(UIImage(systemName: biometricIcon, withConfiguration: config), for: .normal)
        biometricButton.setTitle("  Use \(biometricManager.biometricDisplayName)", for: .normal)
        biometricButton.titleLabel?.font = .systemFont(ofSize: 16, weight: .medium)
        biometricButton.addTarget(self, action: #selector(biometricButtonTapped), for: .touchUpInside)
        biometricButton.isHidden = true
        
        // Error Label
        errorLabel.textColor = .systemRed
        errorLabel.font = .systemFont(ofSize: 14)
        errorLabel.textAlignment = .center
        errorLabel.numberOfLines = 0
        errorLabel.isHidden = true
        
        // Activity Indicator
        activityIndicator.hidesWhenStopped = true
        
        // Stack View
        stackView.axis = .vertical
        stackView.spacing = 16
        stackView.alignment = .fill
        stackView.translatesAutoresizingMaskIntoConstraints = false
        
        stackView.addArrangedSubview(titleLabel)
        stackView.addArrangedSubview(subtitleLabel)
        stackView.addArrangedSubview(createSpacer(height: 20))
        stackView.addArrangedSubview(errorLabel)
        stackView.addArrangedSubview(usernameTextField)
        stackView.addArrangedSubview(passwordTextField)
        stackView.addArrangedSubview(loginButton)
        stackView.addArrangedSubview(createSpacer(height: 10))
        stackView.addArrangedSubview(biometricButton)
        stackView.addArrangedSubview(activityIndicator)
        
        view.addSubview(stackView)
        
        NSLayoutConstraint.activate([
            stackView.centerYAnchor.constraint(equalTo: view.centerYAnchor, constant: -40),
            stackView.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 32),
            stackView.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -32)
        ])
        
        // Dismiss keyboard on tap
        let tapGesture = UITapGestureRecognizer(target: self, action: #selector(dismissKeyboard))
        view.addGestureRecognizer(tapGesture)
    }
    
    private func createSpacer(height: CGFloat) -> UIView {
        let spacer = UIView()
        spacer.heightAnchor.constraint(equalToConstant: height).isActive = true
        return spacer
    }
    
    private func setupNotifications() {
        NotificationCenter.default.addObserver(
            self,
            selector: #selector(handleBiometricEnrollmentOffer(_:)),
            name: .offerBiometricEnrollment,
            object: nil
        )
    }
    
    // MARK: - Authentication Flow
    
    private func attemptBiometricAuth() {
        setLoading(true)
        
        authManager.attemptBiometricAuthentication()
        
        // Observe state changes
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.5) { [weak self] in
            self?.updateUIFromState()
        }
    }
    
    private func updateUIFromState() {
        setLoading(authManager.isLoading)
        
        if authManager.isAuthenticated {
            onAuthenticationSuccess?()
            return
        }
        
        if let error = authManager.authError {
            showError(error)
        }
        
        if authManager.showPasswordLogin {
            showPasswordFields()
            if authManager.shouldAttemptBiometricAuth {
                biometricButton.isHidden = false
            }
        }
        
        if authManager.showBiometricPrompt {
            biometricButton.isHidden = false
        }
    }
    
    private func showPasswordFields() {
        UIView.animate(withDuration: 0.3) {
            self.usernameTextField.isHidden = false
            self.passwordTextField.isHidden = false
            self.loginButton.isHidden = false
            
            if self.authManager.shouldAttemptBiometricAuth {
                self.biometricButton.isHidden = false
            }
        }
    }
    
    private func showError(_ message: String) {
        errorLabel.text = message
        errorLabel.isHidden = false
        
        UIView.animate(withDuration: 0.3) {
            self.errorLabel.alpha = 1
        }
    }
    
    private func hideError() {
        UIView.animate(withDuration: 0.3) {
            self.errorLabel.alpha = 0
        } completion: { _ in
            self.errorLabel.isHidden = true
        }
    }
    
    private func setLoading(_ loading: Bool) {
        if loading {
            activityIndicator.startAnimating()
            loginButton.isEnabled = false
            biometricButton.isEnabled = false
        } else {
            activityIndicator.stopAnimating()
            loginButton.isEnabled = true
            biometricButton.isEnabled = true
        }
    }
    
    // MARK: - Actions
    
    @objc private func loginButtonTapped() {
        dismissKeyboard()
        hideError()
        
        guard let username = usernameTextField.text, !username.isEmpty else {
            showError("Please enter your username.")
            return
        }
        
        guard let password = passwordTextField.text, !password.isEmpty else {
            showError("Please enter your password.")
            return
        }
        
        setLoading(true)
        
        authManager.loginWithPassword(username: username, password: password)
        
        // Check result after delay (simulating network call)
        DispatchQueue.main.asyncAfter(deadline: .now() + 1.5) { [weak self] in
            self?.updateUIFromState()
        }
    }
    
    @objc private func biometricButtonTapped() {
        hideError()
        attemptBiometricAuth()
        
        // Check result after a brief delay
        DispatchQueue.main.asyncAfter(deadline: .now() + 1.0) { [weak self] in
            self?.updateUIFromState()
        }
    }
    
    @objc private func dismissKeyboard() {
        view.endEditing(true)
    }
    
    @objc private func handleBiometricEnrollmentOffer(_ notification: Notification) {
        guard let token = notification.userInfo?["token"] as? String else { return }
        
        let biometricName = biometricManager.biometricDisplayName
        
        let alert = UIAlertController(
            title: "Enable \(biometricName)?",
            message: "Would you like to use \(biometricName) to sign in next time?",
            preferredStyle: .alert
        )
        
        alert.addAction(UIAlertAction(title: "Enable", style: .default) { [weak self] _ in
            self?.authManager.enableBiometricAuth(withToken: token)
        })
        
        alert.addAction(UIAlertAction(title: "Not Now", style: .cancel))
        
        present(alert, animated: true)
    }
}

// MARK: - Main Content View Controller (Post-Authentication)
class MainContentViewController: UIViewController {
    
    private let authManager = AuthenticationStateManager.shared
    
    override func viewDidLoad() {
        super.viewDidLoad()
        view.backgroundColor = .systemBackground
        
        let label = UILabel()
        label.text = "Welcome! You are authenticated."
        label.font = .systemFont(ofSize: 20, weight: .medium)
        label.textAlignment = .center
        label.translatesAutoresizingMaskIntoConstraints = false
        
        let logoutButton = UIButton(type: .system)
        logoutButton.setTitle("Logout", for: .normal)
        logoutButton.titleLabel?.font = .systemFont(ofSize: 16, weight: .medium)
        logoutButton.addTarget(self, action: #selector(logoutTapped), for: .touchUpInside)
        logoutButton.translatesAutoresizingMaskIntoConstraints = false
        
        let disableBiometricButton = UIButton(type: .system)
        disableBiometricButton.setTitle("Disable Biometric Login", for: .normal)
        disableBiometricButton.setTitleColor(.systemRed, for: .normal)
        disableBiometricButton.addTarget(self, action: #selector(disableBiometricTapped), for: .touchUpInside)
        disableBiometricButton.translatesAutoresizingMaskIntoConstraints = false
        
        view.addSubview(label)
        view.addSubview(logoutButton)
        view.addSubview(disableBiometricButton)
        
        NSLayoutConstraint.activate([
            label.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            label.centerYAnchor.constraint(equalTo: view.centerYAnchor, constant: -40),
            logoutButton.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            logoutButton.topAnchor.constraint(equalTo: label.bottomAnchor, constant: 30),
            disableBiometricButton.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            disableBiometricButton.topAnchor.constraint(equalTo: logoutButton.bottomAnchor, constant: 16)
        ])
    }
    
    @objc private func logoutTapped() {
        authManager.logout()
        navigateToLogin()
    }
    
    @objc private func disableBiometricTapped() {
        let alert = UIAlertController(
            title: "Disable Biometric Login",
            message: "Are you sure you want to disable biometric login? You'll need to enter your password each time.",
            preferredStyle: .alert
        )
        
        alert.addAction(UIAlertAction(title: "Disable", style: .destructive) { [weak self] _ in
            self?.authManager.disableBiometricAuth()
        })
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        
        present(alert, animated: true)
    }
    
    private func navigateToLogin() {
        let loginVC = LoginViewController()
        loginVC.modalPresentationStyle = .fullScreen
        loginVC.onAuthenticationSuccess = { [weak loginVC] in
            loginVC?.dismiss(animated: true)
        }
        present(loginVC, animated: true)
    }
}

