    }
    
    private func showLogin() {
        let loginVC = LoginViewController()
        loginVC.onAuthenticationSuccess = { [weak self] in
            self?.showMainContent()
        }
        window.rootViewController = loginVC
        window.makeKeyAndVisible()
    }
    
    private func showLoginWithBiometric() {
        let loginVC = LoginViewController()
        loginVC.onAuthenticationSuccess = { [weak self] in
            self?.showMainContent()
        }
        window.rootViewController = loginVC
        window.makeKeyAndVisible()
    }
    
    private func showMainContent() {
        let mainVC = MainContentViewController()
        
        UIView.transition(with: window, duration: 0.3, options: .transitionCrossDissolve) {
            self.window.rootViewController = mainVC
        }
    }
}

// MARK: - SceneDelegate Integration Example
class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    
    var window: UIWindow?
    private var coordinator: AppFlowCoordinator?
    
    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = scene as? UIWindowScene else { return }
        
        let window = UIWindow(windowScene: windowScene)
        self.window = window
        
        coordinator = AppFlowCoordinator(window: window)
        coordinator?.start()
    }
    
    func sceneDidBecomeActive(_ scene: UIScene) {
        // Optionally re-authenticate when app becomes active after being in background
    }
    
    func sceneWillResignActive(_ scene: UIScene) {
        // Optionally add a privacy screen overlay
    }
}